from collections import deque
from typing import List

class Solution:
    def removeInvalidParentheses(self, s: str) -> List[str]:
        level = {s}
        while True:
            valid = self.filter_valid(level)
            if valid:
                return valid
            level = {s for s in (self.remove_parentheses(s) for s in level) if s}

    def filter_valid(self, s: set) -> List[str]:
        return [s for s in s if self.is_valid(s)]

    def is_valid(self, s: str) -> bool:
        count = 0
        for c in s:
            if c == '(':
                count += 1
            elif c == ')':
                count -= 1
                if count < 0:
                    return False
        return count == 0

    def remove_parentheses(self, s: str) -> List[str]:
        res = []
        for i in range(len(s)):
            if s[i] in ('(', ')'):
                res.append(s[:i] + s[i+1:])
        return res
